class Solution:
    def matrixScore(self, grid):
        m, n = len(grid), len(grid[0])
        best = 0
        for rmask in range(1 << m):
            rows = []
            for i in range(m):
                flip = (rmask >> i) & 1
                rows.append([c ^ flip for c in grid[i]])
            total = 0
            for j in range(n):
                ones = sum(rows[i][j] for i in range(m))
                ones = max(ones, m - ones)
                total += ones * (1 << (n - 1 - j))
            best = max(best, total)
        return best

