var matrixScore = function(grid) {
    const m = grid.length, n = grid[0].length;
    const g = grid.map(r => r.slice());
    for (let i = 0; i < m; i++) {
        if (g[i][0] === 0) g[i] = g[i].map(c => 1 - c);
    }
    let total = 0;
    for (let j = 0; j < n; j++) {
        let ones = 0;
        for (let i = 0; i < m; i++) ones += g[i][j];
        ones = Math.max(ones, m - ones);
        total += ones * (1 << (n - 1 - j));
    }
    return total;
};
